INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which file is the primary YAML configuration file for an Elasticsearch node, where settings such as `cluster.name` and `node.name` are defined?$ece$, $ece$[{"id":"a","text":"elasticsearch.properties"},{"id":"b","text":"elasticsearch.yml"},{"id":"c","text":"jvm.options"},{"id":"d","text":"log4j2.properties"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$`elasticsearch.yml` in the config directory holds cluster/node/network settings. `jvm.options` tunes the JVM heap, `log4j2.properties` configures logging, and `elasticsearch.properties` does not exist.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which file is the primary YAML configuration file for an Elasticsearch node, where settings such as `cluster.name` and `node.name` are defined?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$In `elasticsearch.yml`, which setting explicitly assigns a node ONLY the master-eligible role and removes the data role?$ece$, $ece$[{"id":"a","text":"node.master: true"},{"id":"b","text":"node.roles: [ master ]"},{"id":"c","text":"node.type: master-only"},{"id":"d","text":"cluster.master.only: true"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Since Elasticsearch 7.9 node roles are declared with the `node.roles` list. `node.roles: [ master ]` makes the node master-eligible and not a data node. The legacy `node.master: true` boolean form is deprecated and does not by itself drop the data role.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$In `elasticsearch.yml`, which setting explicitly assigns a node ONLY the master-eligible role and removes the data role?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$When forming a brand-new multi-node cluster for the first time, which setting names the initial set of master-eligible nodes used to bootstrap the cluster?$ece$, $ece$[{"id":"a","text":"discovery.seed_hosts"},{"id":"b","text":"cluster.initial_master_nodes"},{"id":"c","text":"discovery.zen.minimum_master_nodes"},{"id":"d","text":"gateway.recover_after_nodes"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$`cluster.initial_master_nodes` performs the one-time cluster bootstrap and must be set only on the very first cluster formation. `discovery.seed_hosts` lists addresses for node discovery. `minimum_master_nodes` was removed in 7.0. `gateway.recover_after_nodes` controls recovery, not bootstrap.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery-bootstrap-cluster.html","label":"Elasticsearch Reference — Bootstrap a cluster"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$When forming a brand-new multi-node cluster for the first time, which setting names the initial set of master-eligible nodes used to bootstrap the cluster?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$MULTI$ece$::"QType", $ece$Select ALL true statements about node discovery and cluster formation in Elasticsearch 8.x.$ece$, $ece$[{"id":"a","text":"`discovery.seed_hosts` provides the list of addresses a node probes to find other nodes."},{"id":"b","text":"`cluster.initial_master_nodes` should be removed (or left unset) after the cluster has formed for the first time."},{"id":"c","text":"Every node must list every other node in `discovery.seed_hosts` for the cluster to function."},{"id":"d","text":"Only master-eligible nodes participate in master elections."}]$ece$::jsonb, $ece$["a","b","d"]$ece$::jsonb, $ece$`discovery.seed_hosts` only needs to reference enough master-eligible nodes for discovery to converge — not every node. `cluster.initial_master_nodes` is a one-time bootstrap setting. Only master-eligible nodes vote in elections.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery.html","label":"Elasticsearch Reference — Discovery and cluster formation"},{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Select ALL true statements about node discovery and cluster formation in Elasticsearch 8.x.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which request creates an index named `products` with 3 primary shards and 1 replica?$ece$, $ece$[{"id":"a","text":"PUT products with body {\"settings\":{\"number_of_shards\":3,\"number_of_replicas\":1}}"},{"id":"b","text":"POST products/_create {\"shards\":3,\"replicas\":1}"},{"id":"c","text":"PUT products/_settings {\"index.shards\":3}"},{"id":"d","text":"POST _index/products?shards=3&replicas=1"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$A `PUT /products` with `settings.number_of_shards` and `settings.number_of_replicas` is the Create index API. `number_of_shards` is fixed at creation time; `number_of_replicas` can be changed later via `_settings`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-create-index.html","label":"Elasticsearch Reference — Create index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which request creates an index named `products` with 3 primary shards and 1 replica?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Using the Index API, `PUT my-index/_doc/1` versus `POST my-index/_doc` differ in that:$ece$, $ece$[{"id":"a","text":"PUT requires an explicit document ID; POST auto-generates an ID if none is given."},{"id":"b","text":"POST requires an explicit document ID; PUT auto-generates one."},{"id":"c","text":"PUT only updates, POST only creates."},{"id":"d","text":"There is no difference; both require an ID."}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`PUT /index/_doc/<id>` indexes with a caller-supplied ID (create or overwrite). `POST /index/_doc` without an ID lets Elasticsearch auto-generate one. Use `_create` to fail if the ID already exists.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Using the Index API, `PUT my-index/_doc/1` versus `POST my-index/_doc` differ in that:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$In a `_bulk` request, what is required between each action/metadata line and its optional source document?$ece$, $ece$[{"id":"a","text":"A JSON array wrapping all operations"},{"id":"b","text":"Each line must be a complete JSON object/newline-delimited, and the body must end with a newline"},{"id":"c","text":"A comma separating every operation"},{"id":"d","text":"All operations must target the same document ID"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$The Bulk API uses newline-delimited JSON (NDJSON): an action line followed (for index/create/update) by a source line, each on its own line, with a trailing newline. It is NOT a JSON array and operations are independent.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-bulk.html","label":"Elasticsearch Reference — Bulk API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$In a `_bulk` request, what is required between each action/metadata line and its optional source document?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You must copy all documents from `orders-2023` into a new index `orders-archive` that has a different shard count. Which API is designed for this?$ece$, $ece$[{"id":"a","text":"POST _reindex with source orders-2023 and dest orders-archive"},{"id":"b","text":"POST orders-archive/_clone"},{"id":"c","text":"PUT orders-archive/_settings with number_of_shards"},{"id":"d","text":"POST orders-2023/_split"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `_reindex` API copies documents from a source to a destination index and is the standard way to re-shard or transform data. `_clone` requires an identical shard count and a read-only source; `_split` only multiplies shards.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You must copy all documents from `orders-2023` into a new index `orders-archive` that has a different shard count. Which API is designed for this?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which query analyzes the input text and is the standard choice for full-text search on an analyzed `text` field?$ece$, $ece$[{"id":"a","text":"term"},{"id":"b","text":"match"},{"id":"c","text":"exists"},{"id":"d","text":"ids"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$The `match` query runs the search text through the field analyzer, making it the canonical full-text query. `term` does NOT analyze input and is for exact tokens (keyword/numeric). `exists` and `ids` are structural.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/full-text-queries.html","label":"Elasticsearch Reference — Full text queries"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which query analyzes the input text and is the standard choice for full-text search on an analyzed `text` field?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$In a `bool` query, which clause contributes to the relevance score AND is optional (it boosts matching docs but does not exclude non-matching ones when other clauses match)?$ece$, $ece$[{"id":"a","text":"must"},{"id":"b","text":"filter"},{"id":"c","text":"should"},{"id":"d","text":"must_not"}]$ece$::jsonb, $ece$["c"]$ece$::jsonb, $ece$`should` clauses are optional and contribute to `_score`. `must` is required and scored; `filter` is required but NOT scored (filter context); `must_not` excludes and is not scored.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl-bool-query.html","label":"Elasticsearch Reference — Boolean query"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$In a `bool` query, which clause contributes to the relevance score AND is optional (it boosts matching docs but does not exclude non-matching ones when other clauses match)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You need to return documents where `status` is exactly `"active"` without affecting relevance scoring, for maximum cache reuse. The best approach is:$ece$, $ece$[{"id":"a","text":"A `match` query in must"},{"id":"b","text":"A `term` query in the bool `filter` clause"},{"id":"c","text":"A `match_phrase` query in should"},{"id":"d","text":"A `wildcard` query in must"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Exact-value matching belongs in a `term` query, and placing it in `filter` (filter context) skips scoring and enables filter caching. `match`/`match_phrase` analyze text and run in query context.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-filter-context.html","label":"Elasticsearch Reference — Query and filter context"},{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/term-level-queries.html","label":"Elasticsearch Reference — Term-level queries"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You need to return documents where `status` is exactly `"active"` without affecting relevance scoring, for maximum cache reuse. The best approach is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which query searches the same text across multiple fields (e.g. `title` and `body`) in one clause?$ece$, $ece$[{"id":"a","text":"multi_match"},{"id":"b","text":"match_all"},{"id":"c","text":"terms"},{"id":"d","text":"dis_max only with manual per-field match"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`multi_match` runs a `match` against several fields with configurable type (best_fields, most_fields, cross_fields, phrase). `match_all` matches everything; `terms` is exact multi-value term matching.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/full-text-queries.html","label":"Elasticsearch Reference — Full text queries"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which query searches the same text across multiple fields (e.g. `title` and `body`) in one clause?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which statement about `text` versus `keyword` field types is correct?$ece$, $ece$[{"id":"a","text":"text is analyzed/tokenized for full-text search; keyword is stored as a single exact token for filtering, sorting and aggregations."},{"id":"b","text":"keyword is analyzed for full-text search; text is not analyzed."},{"id":"c","text":"Both are analyzed identically."},{"id":"d","text":"text supports aggregations by default; keyword does not."}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$A `text` field is passed through an analyzer and tokenized for relevance search but is not efficient for aggregations/sorting (fielddata disabled by default). A `keyword` field is indexed verbatim and is used for exact match, sort, and aggregations.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping-types.html","label":"Elasticsearch Reference — Field data types"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which statement about `text` versus `keyword` field types is correct?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You want a single source field indexed both as analyzed `text` (for search) and as `keyword` (for aggregations). The idiomatic mapping uses:$ece$, $ece$[{"id":"a","text":"Two separate top-level fields you must populate yourself"},{"id":"b","text":"A multi-field: a `text` field with a `fields.keyword` sub-field of type keyword"},{"id":"c","text":"A `runtime` field of type keyword"},{"id":"d","text":"The `copy_to` parameter pointing to itself"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Multi-fields index the same value multiple ways. The common pattern is a `text` field with `fields: { keyword: { type: "keyword", ignore_above: 256 } }`. Runtime fields are computed at query time, not indexed for aggregations efficiently.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/multi-fields.html","label":"Elasticsearch Reference — multi-fields"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You want a single source field indexed both as analyzed `text` (for search) and as `keyword` (for aggregations). The idiomatic mapping uses:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$With dynamic mapping enabled (the default), what happens when you index a document containing a previously unseen field `price` with a JSON number?$ece$, $ece$[{"id":"a","text":"The document is rejected until you add an explicit mapping."},{"id":"b","text":"Elasticsearch dynamically adds a mapping for `price` (e.g. as long or float) and indexes the document."},{"id":"c","text":"The field is stored but never indexed or searchable."},{"id":"d","text":"The whole index becomes read-only."}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Default dynamic mapping detects the JSON type and creates a field mapping automatically. Setting `dynamic: strict` would reject unknown fields; `dynamic: false` would store but not index them.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$With dynamic mapping enabled (the default), what happens when you index a document containing a previously unseen field `price` with a JSON number?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A `runtime` field defined in the mapping is best described as:$ece$, $ece$[{"id":"a","text":"A field evaluated at query time via a script (or from source), not indexed at ingest, trading query speed for schema flexibility."},{"id":"b","text":"A field that is indexed faster than normal fields."},{"id":"c","text":"A field that can only be a date."},{"id":"d","text":"An alias to another index."}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Runtime fields are computed when the query runs (or at index time if backed by a script-on-index), enabling schema-on-read without reindexing — at the cost of per-query computation versus pre-indexed fields.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/runtime.html","label":"Elasticsearch Reference — Runtime fields"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `runtime` field defined in the mapping is best described as:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$A cluster health status of `yellow` means:$ece$, $ece$[{"id":"a","text":"All primary AND replica shards are allocated."},{"id":"b","text":"All primary shards are allocated but at least one replica shard is unallocated."},{"id":"c","text":"At least one primary shard is unallocated (data missing)."},{"id":"d","text":"The cluster is read-only."}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Green = all primaries and replicas allocated. Yellow = all primaries allocated but some replicas unassigned (still fully searchable, reduced redundancy). Red = at least one primary unassigned.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-health.html","label":"Elasticsearch Reference — Cluster health API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A cluster health status of `yellow` means:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A replica shard is stuck unassigned. Which API explains WHY the allocation decision was made?$ece$, $ece$[{"id":"a","text":"GET _cluster/allocation/explain"},{"id":"b","text":"GET _cat/shards?why"},{"id":"c","text":"POST _cluster/reroute?explain_only=true"},{"id":"d","text":"GET _nodes/stats/allocation"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The cluster allocation explain API returns the deciders and reason a shard is or is not allocated. `_cat/shards` shows state but not the decision reasoning.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-allocation-explain.html","label":"Elasticsearch Reference — Cluster allocation explain API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A replica shard is stuck unassigned. Which API explains WHY the allocation decision was made?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which aggregation type groups documents into buckets, such as one bucket per distinct value of a keyword field?$ece$, $ece$[{"id":"a","text":"metric aggregation (e.g. avg)"},{"id":"b","text":"bucket aggregation (e.g. terms)"},{"id":"c","text":"pipeline aggregation (e.g. derivative)"},{"id":"d","text":"matrix aggregation only"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Bucket aggregations like `terms`, `date_histogram`, and `range` group documents. Metric aggregations compute values (avg, sum) over documents; pipeline aggregations operate on the output of other aggregations.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which aggregation type groups documents into buckets, such as one bucket per distinct value of a keyword field?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$An ingest pipeline is used to:$ece$, $ece$[{"id":"a","text":"Transform/enrich documents with processors BEFORE they are indexed."},{"id":"b","text":"Replicate shards across nodes."},{"id":"c","text":"Stream query results to a client."},{"id":"d","text":"Schedule snapshots."}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Ingest pipelines run on ingest-role nodes and apply processors (set, rename, grok, geoip, etc.) to documents before indexing. They do not handle replication, search streaming, or snapshots.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/ingest.html","label":"Elasticsearch Reference — Ingest pipelines"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$An ingest pipeline is used to:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Where is the JVM heap size for an Elasticsearch node configured?$ece$, $ece$[{"id":"a","text":"In `elasticsearch.yml` under `index.heap`"},{"id":"b","text":"In `jvm.options` (or a file in `jvm.options.d/`) via `-Xms`/`-Xmx`"},{"id":"c","text":"In `log4j2.properties`"},{"id":"d","text":"Via the `_cluster/settings` API"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Heap is a JVM concern set in `jvm.options` (or drop-in files in `jvm.options.d/`) using `-Xms`/`-Xmx`. It is not an Elasticsearch YAML or dynamic cluster setting; `log4j2.properties` only configures logging.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Where is the JVM heap size for an Elasticsearch node configured?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which setting provides the list of master-eligible node addresses that a starting node probes to discover the cluster?$ece$, $ece$[{"id":"a","text":"discovery.seed_hosts"},{"id":"b","text":"cluster.initial_master_nodes"},{"id":"c","text":"network.publish_host"},{"id":"d","text":"transport.profiles.default.port"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`discovery.seed_hosts` lists addresses used for node discovery (the seed hosts providers). `cluster.initial_master_nodes` is a one-time bootstrap-only setting; `network.publish_host` and transport profiles relate to binding/transport, not discovery seeding.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery.html","label":"Elasticsearch Reference — Discovery and cluster formation"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting provides the list of master-eligible node addresses that a starting node probes to discover the cluster?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which `node.roles` value makes a node store warm-tier shards for ILM data-tier allocation?$ece$, $ece$[{"id":"a","text":"node.roles: [ data_warm ]"},{"id":"b","text":"node.roles: [ warm ]"},{"id":"c","text":"node.roles: [ data, tier_warm ]"},{"id":"d","text":"node.tier: warm"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Data tiers use dedicated roles `data_hot`, `data_warm`, `data_cold`, `data_frozen` (and generic `data`/`data_content`). The exact role is `data_warm`; `warm`, `tier_warm`, and `node.tier` are not valid role keywords.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which `node.roles` value makes a node store warm-tier shards for ILM data-tier allocation?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which setting names the cluster so that nodes only join the intended cluster?$ece$, $ece$[{"id":"a","text":"cluster.name"},{"id":"b","text":"node.name"},{"id":"c","text":"cluster.uuid"},{"id":"d","text":"discovery.cluster"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`cluster.name` defines the logical cluster a node belongs to — nodes with the same `cluster.name` form one cluster. `node.name` identifies an individual node; `cluster.uuid` is generated automatically and not user-set.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting names the cluster so that nodes only join the intended cluster?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$How are secure/sensitive settings (such as the S3 repository access key) stored for an Elasticsearch node?$ece$, $ece$[{"id":"a","text":"As plaintext in elasticsearch.yml"},{"id":"b","text":"In the Elasticsearch keystore via the elasticsearch-keystore tool"},{"id":"c","text":"In jvm.options"},{"id":"d","text":"As environment variables only"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Sensitive settings belong in the encrypted Elasticsearch keystore, managed with `bin/elasticsearch-keystore add ...`. Putting credentials plaintext in `elasticsearch.yml` is insecure; `jvm.options` is JVM tuning only.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$How are secure/sensitive settings (such as the S3 repository access key) stored for an Elasticsearch node?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$TRUE_FALSE$ece$::"QType", $ece$True or False: `cluster.initial_master_nodes` should be left configured permanently on every node so the cluster can re-bootstrap after a full restart.$ece$, $ece$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$False. `cluster.initial_master_nodes` is a one-time bootstrap setting used only for the very first cluster formation; leaving it set can cause split-brain on later restarts. After formation it should be removed.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery-bootstrap-cluster.html","label":"Elasticsearch Reference — Bootstrap a cluster"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$True or False: `cluster.initial_master_nodes` should be left configured permanently on every node so the cluster can re-bootstrap after a full restart.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which command-line tool generates an enrollment token so Kibana can connect securely to an 8.x cluster?$ece$, $ece$[{"id":"a","text":"bin/elasticsearch-create-enrollment-token -s kibana"},{"id":"b","text":"bin/elasticsearch-setup-passwords kibana"},{"id":"c","text":"bin/elasticsearch-certutil kibana"},{"id":"d","text":"bin/kibana-enroll"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`elasticsearch-create-enrollment-token -s kibana` mints a Kibana enrollment token containing the CA fingerprint and connection info. `elasticsearch-certutil` generates certs; `setup-passwords` was the pre-8.x reset tool.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which command-line tool generates an enrollment token so Kibana can connect securely to an 8.x cluster?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which setting controls the HTTP port Elasticsearch listens on for the REST API?$ece$, $ece$[{"id":"a","text":"http.port"},{"id":"b","text":"transport.port"},{"id":"c","text":"network.bind_port"},{"id":"d","text":"rest.api.port"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`http.port` (default 9200) is the REST/HTTP layer port. `transport.port` (default 9300) is for inter-node communication. `network.bind_port` and `rest.api.port` are not real settings.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting controls the HTTP port Elasticsearch listens on for the REST API?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$MULTI$ece$::"QType", $ece$Select ALL recommended production bootstrap/OS settings for an Elasticsearch node.$ece$, $ece$[{"id":"a","text":"Increase the max file descriptors (e.g. 65535) for the elasticsearch user."},{"id":"b","text":"Increase `vm.max_map_count` to at least 262144."},{"id":"c","text":"Disable swap or enable `bootstrap.memory_lock: true`."},{"id":"d","text":"Run Elasticsearch as the root user for maximum permissions."}]$ece$::jsonb, $ece$["a","b","c"]$ece$::jsonb, $ece$High file descriptor limits, `vm.max_map_count >= 262144`, and disabling swap (or memory-locking) are documented production prerequisites. Running as root is explicitly discouraged for security.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Select ALL recommended production bootstrap/OS settings for an Elasticsearch node.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which API permanently deletes a single document by id from an index?$ece$, $ece$[{"id":"a","text":"DELETE <index>/_doc/<id>"},{"id":"b","text":"POST <index>/_remove/<id>"},{"id":"c","text":"DELETE <index>/_settings/<id>"},{"id":"d","text":"POST <index>/_delete_doc"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`DELETE /<index>/_doc/<id>` removes a document by id. To delete by query you use `_delete_by_query`. The other forms are not valid Elasticsearch endpoints.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API permanently deletes a single document by id from an index?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which API deletes all documents matching a query without deleting the index itself?$ece$, $ece$[{"id":"a","text":"POST <index>/_delete_by_query"},{"id":"b","text":"DELETE <index>"},{"id":"c","text":"POST <index>/_truncate"},{"id":"d","text":"PUT <index>/_settings {\"blocks.write\": true}"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`_delete_by_query` removes documents matching a Query DSL query while keeping the index. `DELETE <index>` drops the whole index; there is no `_truncate` API; a write block only prevents new writes.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-update-by-query.html","label":"Elasticsearch Reference — Update By Query API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API deletes all documents matching a query without deleting the index itself?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You index `PUT books/_doc/1` twice with different bodies. What is the resulting `_version` and document state?$ece$, $ece$[{"id":"a","text":"Two documents with id 1 exist"},{"id":"b","text":"The document is fully replaced and `_version` increments to 2"},{"id":"c","text":"The second request is rejected as a duplicate"},{"id":"d","text":"Only changed fields are merged (partial update)"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Indexing with the same id replaces the whole document and increments `_version`. Ids are unique within an index. Partial merges require the `_update` API; `_create` would reject the second write.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You index `PUT books/_doc/1` twice with different bodies. What is the resulting `_version` and document state?$ece$);
