INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$To halve the primary shard count of a read-only index from 6 to 3, which API is appropriate?$ece$, $ece$[{"id":"a","text":"POST <index>/_shrink/<target>"},{"id":"b","text":"POST <index>/_split/<target>"},{"id":"c","text":"POST <index>/_clone/<target>"},{"id":"d","text":"POST _reindex with fewer replicas"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `_shrink` API reduces the number of primary shards (target must divide the source count); the source must be read-only and its shards co-located. `_split` only increases shards; `_clone` keeps the same count.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$To halve the primary shard count of a read-only index from 6 to 3, which API is appropriate?$ece$);
