INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A Snapshot Lifecycle Management (SLM) policy is responsible for:$ece$, $ece$[{"id":"a","text":"Automatically creating snapshots on a schedule and applying retention"},{"id":"b","text":"Transitioning indices through hot/warm/cold phases"},{"id":"c","text":"Rerouting shards between nodes"},{"id":"d","text":"Defining index mappings"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$SLM schedules automatic snapshots to a registered repository and enforces retention. ILM (not SLM) handles hot/warm/cold phase transitions; shard rerouting and mappings are unrelated.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/snapshot-restore.html","label":"Elasticsearch Reference — Snapshot and restore"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A Snapshot Lifecycle Management (SLM) policy is responsible for:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which API updates a transient/persistent cluster-wide setting such as `cluster.routing.allocation.enable`?$ece$, $ece$[{"id":"a","text":"PUT _cluster/settings"},{"id":"b","text":"PUT _settings"},{"id":"c","text":"PUT <index>/_settings"},{"id":"d","text":"POST _cluster/reroute"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`PUT _cluster/settings` changes persistent/transient cluster-level settings. `PUT <index>/_settings` is per-index; `_cluster/reroute` manually moves shards rather than changing settings.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API updates a transient/persistent cluster-wide setting such as `cluster.routing.allocation.enable`?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Before a rolling upgrade/restart, disabling shard allocation prevents unnecessary rebalancing. The correct setting is:$ece$, $ece$[{"id":"a","text":"cluster.routing.allocation.enable: \"primaries\" (or \"none\")"},{"id":"b","text":"index.blocks.write: true"},{"id":"c","text":"discovery.type: single-node"},{"id":"d","text":"cluster.routing.rebalance.enable: \"always\""}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Setting `cluster.routing.allocation.enable` to `none`/`primaries` during a rolling restart stops replica reallocation churn while a node is briefly down. A write block stops indexing, not allocation.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-allocation-explain.html","label":"Elasticsearch Reference — Cluster allocation explain API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Before a rolling upgrade/restart, disabling shard allocation prevents unnecessary rebalancing. The correct setting is:$ece$);
