INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which aggregation buckets numeric values into user-defined ranges such as 0–50, 50–100, 100+?$ece$, $ece$[{"id":"a","text":"range aggregation"},{"id":"b","text":"avg aggregation"},{"id":"c","text":"cardinality aggregation"},{"id":"d","text":"top_hits aggregation"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `range` (or `date_range`) bucket aggregation groups documents into explicit numeric/date ranges. `avg`/`cardinality` are metrics; `top_hits` returns sample docs per bucket.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which aggregation buckets numeric values into user-defined ranges such as 0–50, 50–100, 100+?$ece$);
