INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$How do you attach a default ingest pipeline so every write to an index is processed automatically?$ece$, $ece$[{"id":"a","text":"Set index.default_pipeline in the index settings"},{"id":"b","text":"Add a processor to elasticsearch.yml"},{"id":"c","text":"Use a search template"},{"id":"d","text":"Set cluster.routing.allocation.pipeline"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The index setting `index.default_pipeline` (or `index.final_pipeline`) runs a pipeline on every indexed document without specifying `?pipeline=` per request. Pipelines are not configured in `elasticsearch.yml`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/ingest.html","label":"Elasticsearch Reference — Ingest pipelines"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P1$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$How do you attach a default ingest pipeline so every write to an index is processed automatically?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$On a fresh Elasticsearch 8.x install, what is true about the security configuration by default?$ece$, $ece$[{"id":"a","text":"Security is disabled and must be enabled manually."},{"id":"b","text":"Security (TLS + authentication) is enabled automatically on first start, with an enrollment token generated for additional nodes/Kibana."},{"id":"c","text":"Only API key auth is available; TLS is never configured."},{"id":"d","text":"Security requires a paid license."}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Since 8.0 the Elastic Stack security features are on by default: TLS for the transport and HTTP layers is auto-configured and an enrollment token is printed for joining nodes and Kibana. Basic security is free.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$On a fresh Elasticsearch 8.x install, what is true about the security configuration by default?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which `node.roles` value makes a node a coordinating-only node (no master, data, or ingest duties)?$ece$, $ece$[{"id":"a","text":"node.roles: [ coordinating ]"},{"id":"b","text":"node.roles: []"},{"id":"c","text":"node.roles: [ none ]"},{"id":"d","text":"node.coordinating: true"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$A coordinating-only node is configured with an EMPTY roles list: `node.roles: []`. There is no explicit `coordinating` role keyword — every node implicitly coordinates; removing all other roles yields a coordinating-only node.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which `node.roles` value makes a node a coordinating-only node (no master, data, or ingest duties)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which setting in `elasticsearch.yml` controls the network address the node binds to and publishes for client and inter-node traffic?$ece$, $ece$[{"id":"a","text":"network.host"},{"id":"b","text":"http.cors.host"},{"id":"c","text":"path.data"},{"id":"d","text":"cluster.routing.host"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`network.host` sets the bind/publish address (e.g. `0.0.0.0` or a specific IP). `path.data` is the data directory; `http.cors.host` is CORS-only; `cluster.routing.host` is not a setting.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting in `elasticsearch.yml` controls the network address the node binds to and publishes for client and inter-node traffic?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$MULTI$ece$::"QType", $ece$Select ALL true statements about JVM heap and system configuration for an Elasticsearch node.$ece$, $ece$[{"id":"a","text":"Heap is typically set no more than ~50% of physical RAM and below the ~32 GB compressed-oops threshold."},{"id":"b","text":"Min and max heap (Xms/Xmx) should be set to the same value to avoid resize pauses."},{"id":"c","text":"Swapping should be disabled (e.g. bootstrap.memory_lock: true) for predictable performance."},{"id":"d","text":"Heap size is configured in elasticsearch.yml under index.heap."}]$ece$::jsonb, $ece$["a","b","c"]$ece$::jsonb, $ece$Heap is set via `jvm.options` (or JVM env), NOT `elasticsearch.yml`/`index.heap`. Best practice: Xms == Xmx, ≤ 50% RAM and under ~32 GB, and lock memory to avoid swapping.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Select ALL true statements about JVM heap and system configuration for an Elasticsearch node.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which index setting CANNOT be changed after the index is created?$ece$, $ece$[{"id":"a","text":"number_of_replicas"},{"id":"b","text":"refresh_interval"},{"id":"c","text":"number_of_shards"},{"id":"d","text":"index.blocks.read_only"}]$ece$::jsonb, $ece$["c"]$ece$::jsonb, $ece$`number_of_shards` (primary shard count) is fixed at creation; changing it requires reindex/split/shrink. Replicas, refresh interval, and blocks are dynamic settings updatable via `_settings`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-create-index.html","label":"Elasticsearch Reference — Create index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which index setting CANNOT be changed after the index is created?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You need to add a `processed: true` field to every document in `logs-*` that matches a query, in place. Which API does this?$ece$, $ece$[{"id":"a","text":"POST logs-*/_update_by_query with a script"},{"id":"b","text":"POST _reindex into the same index"},{"id":"c","text":"PUT logs-*/_mapping"},{"id":"d","text":"POST logs-*/_forcemerge"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`_update_by_query` runs a script over documents matching a query and updates them in place. Reindexing into the same index is unsafe; `_mapping` changes schema only; `_forcemerge` merges segments.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-update-by-query.html","label":"Elasticsearch Reference — Update By Query API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You need to add a `processed: true` field to every document in `logs-*` that matches a query, in place. Which API does this?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$An alias `orders` points to `orders-v1`. To switch readers to `orders-v2` atomically with zero downtime, you should:$ece$, $ece$[{"id":"a","text":"Delete the alias, then recreate it on orders-v2"},{"id":"b","text":"POST _aliases with one atomic action: remove orders from orders-v1 AND add it to orders-v2"},{"id":"c","text":"Rename orders-v1 to orders-v2"},{"id":"d","text":"Set orders-v1 read-only"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$The `_aliases` API applies multiple add/remove actions atomically in one request, enabling zero-downtime cutover. Delete-then-recreate leaves a window with no alias.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/aliases.html","label":"Elasticsearch Reference — Aliases"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$An alias `orders` points to `orders-v1`. To switch readers to `orders-v2` atomically with zero downtime, you should:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 4, $ece$SINGLE$ece$::"QType", $ece$In a `_bulk` request, one of 500 operations fails with a mapping conflict. What happens to the rest?$ece$, $ece$[{"id":"a","text":"The entire bulk request is rolled back."},{"id":"b","text":"Only the failing operation fails; the others succeed, and the response `errors` flag is true with per-item status."},{"id":"c","text":"All operations after the failing one are skipped."},{"id":"d","text":"The index is locked."}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Bulk operations are independent. A failure affects only that item; the response has `errors: true` and a per-item `status`/`error`. There is no transactional rollback.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-bulk.html","label":"Elasticsearch Reference — Bulk API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$In a `_bulk` request, one of 500 operations fails with a mapping conflict. What happens to the rest?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$The key difference between query context and filter context is:$ece$, $ece$[{"id":"a","text":"Query context computes a relevance `_score`; filter context only answers yes/no and is cacheable."},{"id":"b","text":"Filter context computes a score; query context does not."},{"id":"c","text":"Both always compute a score."},{"id":"d","text":"Filter context can only be used on text fields."}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$In query context a clause contributes to `_score` (how well it matches). In filter context the question is only "does it match?" — no scoring, and results are cacheable for speed.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-filter-context.html","label":"Elasticsearch Reference — Query and filter context"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$The key difference between query context and filter context is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which query finds documents with a numeric `age` between 18 and 30 inclusive?$ece$, $ece$[{"id":"a","text":"range query on age with gte:18, lte:30"},{"id":"b","text":"term query on age with value \"18-30\""},{"id":"c","text":"match query on age with \"18 30\""},{"id":"d","text":"exists query on age"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `range` query with `gte`/`lte` (or `gt`/`lt`) handles numeric and date ranges. `term`/`match` are not range operators; `exists` only checks presence.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/term-level-queries.html","label":"Elasticsearch Reference — Term-level queries"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which query finds documents with a numeric `age` between 18 and 30 inclusive?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You want documents that MUST match `category:books`, SHOULD prefer `author:asimov`, and MUST NOT be `discontinued:true`. Which compound query expresses this?$ece$, $ece$[{"id":"a","text":"A `bool` query with `must` (category), `should` (author), and `must_not` (discontinued)"},{"id":"b","text":"A `dis_max` query"},{"id":"c","text":"A `constant_score` query"},{"id":"d","text":"A single `match` query with all conditions concatenated"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `bool` query composes `must`, `should`, `must_not`, and `filter` clauses — exactly mapping required, preferred, and excluded conditions.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl-bool-query.html","label":"Elasticsearch Reference — Boolean query"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You want documents that MUST match `category:books`, SHOULD prefer `author:asimov`, and MUST NOT be `discontinued:true`. Which compound query expresses this?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 4, $ece$SINGLE$ece$::"QType", $ece$Relevance scoring in Elasticsearch by default uses which similarity algorithm?$ece$, $ece$[{"id":"a","text":"TF-IDF (classic Lucene)"},{"id":"b","text":"BM25 (Okapi BM25)"},{"id":"c","text":"PageRank"},{"id":"d","text":"Cosine similarity on raw term counts"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Since Lucene 6 / Elasticsearch 5, the default similarity is BM25, which improves on classic TF-IDF with term-frequency saturation and length normalization. PageRank/cosine are not the default text scoring model.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl.html","label":"Elasticsearch Reference — Query DSL"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Relevance scoring in Elasticsearch by default uses which similarity algorithm?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which API lets you test how a specific analyzer tokenizes a piece of text WITHOUT indexing anything?$ece$, $ece$[{"id":"a","text":"GET _analyze (the Analyze API)"},{"id":"b","text":"GET _tokens"},{"id":"c","text":"POST _simulate/text"},{"id":"d","text":"GET _mapping/_test"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `_analyze` API returns the token stream produced by an analyzer (or a custom char_filter/tokenizer/filter chain) for given text, with no document indexed. The others are not real APIs for this.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-analyze.html","label":"Elasticsearch Reference — Analyze API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API lets you test how a specific analyzer tokenizes a piece of text WITHOUT indexing anything?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$An analyzer in Elasticsearch is composed, in order, of:$ece$, $ece$[{"id":"a","text":"tokenizer → char filters → token filters"},{"id":"b","text":"zero or more character filters → exactly one tokenizer → zero or more token filters"},{"id":"c","text":"one token filter → many tokenizers"},{"id":"d","text":"a mapping → a query → a result"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$An analyzer = optional character filter(s), then exactly ONE tokenizer, then optional token filter(s). Char filters preprocess raw text, the tokenizer splits into tokens, token filters modify the token stream (lowercase, stop, stemming).$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis-custom-analyzer.html","label":"Elasticsearch Reference — Create a custom analyzer"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$An analyzer in Elasticsearch is composed, in order, of:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You define a custom analyzer with a `lowercase` token filter and an `html_strip` char filter. Which order is correct in the analysis chain?$ece$, $ece$[{"id":"a","text":"html_strip (char filter) runs first on raw text, then the tokenizer, then lowercase (token filter)"},{"id":"b","text":"lowercase runs first, then html_strip"},{"id":"c","text":"Both run after the tokenizer"},{"id":"d","text":"Char filters and token filters cannot be combined"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Character filters (e.g. `html_strip`) operate on the raw character stream BEFORE tokenization. Token filters (e.g. `lowercase`) operate on tokens AFTER the tokenizer. They are routinely combined in a custom analyzer.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis-custom-analyzer.html","label":"Elasticsearch Reference — Create a custom analyzer"},{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You define a custom analyzer with a `lowercase` token filter and an `html_strip` char filter. Which order is correct in the analysis chain?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Once an index is created, changing the type of an existing field (e.g. `text` → `keyword`) requires:$ece$, $ece$[{"id":"a","text":"A simple PUT _mapping update on the existing field"},{"id":"b","text":"Creating a new index with the corrected mapping and reindexing the data"},{"id":"c","text":"Restarting the cluster"},{"id":"d","text":"Setting dynamic: true"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$You cannot change the type of an existing mapped field in place. The standard procedure is to create a new index with the desired mapping and `_reindex` into it (often behind an alias for a clean cutover).$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"},{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Once an index is created, changing the type of an existing field (e.g. `text` → `keyword`) requires:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which feature automatically transitions indices through hot/warm/cold/delete phases based on age or size?$ece$, $ece$[{"id":"a","text":"Index Lifecycle Management (ILM)"},{"id":"b","text":"Snapshot Lifecycle Management only"},{"id":"c","text":"Cross-cluster replication"},{"id":"d","text":"The reindex API on a schedule"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$ILM applies a policy with phases (hot, warm, cold, frozen, delete) and actions (rollover, shrink, force-merge, delete) based on age/size/doc count. SLM manages snapshots, not index phases.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which feature automatically transitions indices through hot/warm/cold/delete phases based on age or size?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Before you can take a snapshot, you must first:$ece$, $ece$[{"id":"a","text":"Register a snapshot repository (e.g. shared FS or S3) via the _snapshot API"},{"id":"b","text":"Set the cluster to read-only"},{"id":"c","text":"Stop all indexing"},{"id":"d","text":"Delete all replicas"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Snapshots are written to a registered repository. You register one with `PUT _snapshot/<repo>` (fs, s3, gcs, azure) before creating snapshots. Indexing can continue; snapshots are incremental and non-blocking.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/snapshot-restore.html","label":"Elasticsearch Reference — Snapshot and restore"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Before you can take a snapshot, you must first:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which is a METRIC aggregation (computes a value over a set of documents)?$ece$, $ece$[{"id":"a","text":"terms"},{"id":"b","text":"date_histogram"},{"id":"c","text":"avg"},{"id":"d","text":"filters"}]$ece$::jsonb, $ece$["c"]$ece$::jsonb, $ece$`avg` (also sum, min, max, stats, cardinality) is a metric aggregation. `terms`, `date_histogram`, and `filters` are bucket aggregations that group documents.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which is a METRIC aggregation (computes a value over a set of documents)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A pipeline aggregation such as `derivative` or `cumulative_sum`:$ece$, $ece$[{"id":"a","text":"Operates on the output (buckets/metrics) of another aggregation, not directly on documents"},{"id":"b","text":"Replaces the need for a query"},{"id":"c","text":"Runs only on keyword fields"},{"id":"d","text":"Is a type of ingest processor"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Pipeline aggregations consume the results of other aggregations (e.g. a metric inside a date_histogram) to compute moving functions, derivatives, cumulative sums, bucket scripts, etc.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations-pipeline.html","label":"Elasticsearch Reference — Pipeline aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A pipeline aggregation such as `derivative` or `cumulative_sum`:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which file configures the logging behavior of an Elasticsearch node?$ece$, $ece$[{"id":"a","text":"log4j2.properties"},{"id":"b","text":"elasticsearch.yml"},{"id":"c","text":"jvm.options"},{"id":"d","text":"logging.json"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Elasticsearch uses Log4j2; `log4j2.properties` in the config directory defines appenders/levels. `elasticsearch.yml` is cluster/node config and `jvm.options` is JVM tuning.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which file configures the logging behavior of an Elasticsearch node?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$In `node.roles`, which combination yields a node that holds data AND can run ingest pipelines but is NOT master-eligible?$ece$, $ece$[{"id":"a","text":"node.roles: [ data, ingest ]"},{"id":"b","text":"node.roles: [ master, data, ingest ]"},{"id":"c","text":"node.roles: []"},{"id":"d","text":"node.roles: [ master ]"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`[ data, ingest ]` gives data storage + pipeline execution while omitting `master`, so the node cannot be elected master. An empty list is coordinating-only; including `master` makes it master-eligible.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$In `node.roles`, which combination yields a node that holds data AND can run ingest pipelines but is NOT master-eligible?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which setting list seeds discovery by pointing at the addresses of master-eligible nodes?$ece$, $ece$[{"id":"a","text":"discovery.seed_hosts"},{"id":"b","text":"cluster.initial_master_nodes"},{"id":"c","text":"gateway.expected_data_nodes"},{"id":"d","text":"transport.tcp.compress"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`discovery.seed_hosts` is the unicast seed list used to find peers. `cluster.initial_master_nodes` is bootstrap-only; `gateway.expected_data_nodes` gates recovery; transport compression is unrelated.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery.html","label":"Elasticsearch Reference — Discovery and cluster formation"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting list seeds discovery by pointing at the addresses of master-eligible nodes?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which command adds a secure setting (e.g. an S3 secret key) to the node keystore?$ece$, $ece$[{"id":"a","text":"bin/elasticsearch-keystore add s3.client.default.secret_key"},{"id":"b","text":"bin/elasticsearch-certutil add secret_key"},{"id":"c","text":"PUT _cluster/settings with the secret"},{"id":"d","text":"Add it to jvm.options"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`elasticsearch-keystore add <setting>` stores encrypted secure settings. `certutil` is for certificates; secrets must not go into `_cluster/settings` plaintext or `jvm.options`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which command adds a secure setting (e.g. an S3 secret key) to the node keystore?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which built-in superuser account is created/managed for bootstrapping a secured 8.x cluster?$ece$, $ece$[{"id":"a","text":"elastic"},{"id":"b","text":"admin"},{"id":"c","text":"root"},{"id":"d","text":"superuser"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The built-in `elastic` user is the bootstrap superuser; its password can be (re)set with `elasticsearch-reset-password`. `admin`/`root`/`superuser` are not the default built-in account name (superuser is a role).$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which built-in superuser account is created/managed for bootstrapping a secured 8.x cluster?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$TRUE_FALSE$ece$::"QType", $ece$True or False: A coordinating-only node still participates in master elections.$ece$, $ece$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$False. A coordinating-only node has `node.roles: []` and is not master-eligible, so it does not vote in elections. It only routes requests and gathers/merges results.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$True or False: A coordinating-only node still participates in master elections.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$For a production node bound to a routable IP, which bootstrap check commonly fails if the OS limit is too low?$ece$, $ece$[{"id":"a","text":"The vm.max_map_count check (must be >= 262144)"},{"id":"b","text":"The cluster.name presence check"},{"id":"c","text":"The path.logs writable check only"},{"id":"d","text":"The number_of_replicas check"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`vm.max_map_count` must be at least 262144 or the production bootstrap check fails and the node refuses to start. `number_of_replicas` is an index setting, not a bootstrap check.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$For a production node bound to a routable IP, which bootstrap check commonly fails if the OS limit is too low?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which setting identifies an individual node (shown in cluster APIs and logs)?$ece$, $ece$[{"id":"a","text":"node.name"},{"id":"b","text":"cluster.name"},{"id":"c","text":"node.attr.rack"},{"id":"d","text":"node.id"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`node.name` is the human-readable node identifier (defaults to the hostname). `cluster.name` groups nodes; `node.attr.*` are custom allocation attributes; `node.id` is auto-generated, not user-set.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting identifies an individual node (shown in cluster APIs and logs)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You want shard allocation awareness so replicas avoid the same rack as their primary. The first step is to set:$ece$, $ece$[{"id":"a","text":"A custom node attribute (node.attr.rack_id) plus cluster.routing.allocation.awareness.attributes"},{"id":"b","text":"discovery.seed_hosts per rack"},{"id":"c","text":"index.number_of_replicas: 0"},{"id":"d","text":"node.roles: [ data_warm ]"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Allocation awareness uses a custom node attribute (e.g. `node.attr.rack_id`) plus `cluster.routing.allocation.awareness.attributes: rack_id` so Elasticsearch spreads primaries/replicas across racks. The other options are unrelated.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You want shard allocation awareness so replicas avoid the same rack as their primary. The first step is to set:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which call creates an index using an explicit mappings object at creation time?$ece$, $ece$[{"id":"a","text":"PUT my-index with body containing \"mappings\": { \"properties\": { ... } }"},{"id":"b","text":"POST my-index/_mapping/_create"},{"id":"c","text":"PUT my-index/_doc with the mapping"},{"id":"d","text":"POST _create/my-index?mappings=..."}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The Create Index API accepts `settings` and `mappings` in the body of `PUT /my-index`. Mappings cannot be supplied through `_doc`; `_mapping` is for updating an existing index.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-create-index.html","label":"Elasticsearch Reference — Create index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which call creates an index using an explicit mappings object at creation time?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which API merges Lucene segments to reduce their count (commonly run on read-only/older indices)?$ece$, $ece$[{"id":"a","text":"POST <index>/_forcemerge?max_num_segments=1"},{"id":"b","text":"POST <index>/_flush"},{"id":"c","text":"POST <index>/_refresh"},{"id":"d","text":"POST <index>/_shrink"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`_forcemerge` rewrites segments down to a target count, reclaiming deletes and improving read performance — best on indices no longer written to. `_flush` persists the translog; `_refresh` makes docs searchable; `_shrink` changes shard count.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API merges Lucene segments to reduce their count (commonly run on read-only/older indices)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A write to a single document needs to be acknowledged by the primary AND one replica before returning. Which parameter expresses that?$ece$, $ece$[{"id":"a","text":"wait_for_active_shards=2"},{"id":"b","text":"refresh=true"},{"id":"c","text":"timeout=2s"},{"id":"d","text":"routing=2"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`wait_for_active_shards` requires that many shard copies (primary + replicas) be active before the operation proceeds. `refresh` controls visibility; `timeout` bounds the wait; `routing` selects a shard.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A write to a single document needs to be acknowledged by the primary AND one replica before returning. Which parameter expresses that?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which combination correctly upserts: update the document if it exists, otherwise insert it?$ece$, $ece$[{"id":"a","text":"POST <index>/_update/<id> with \"doc\" and \"doc_as_upsert\": true (or an \"upsert\" object)"},{"id":"b","text":"PUT <index>/_doc/<id> with op_type=create"},{"id":"c","text":"POST <index>/_bulk with only delete actions"},{"id":"d","text":"POST <index>/_reindex"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `_update` API with `doc_as_upsert: true` (or an explicit `upsert` object) updates an existing doc or creates it if missing. `op_type=create` fails when the id exists rather than upserting.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which combination correctly upserts: update the document if it exists, otherwise insert it?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A write alias used by a data stream / rollover pattern must have exactly one index designated as:$ece$, $ece$[{"id":"a","text":"is_write_index: true"},{"id":"b","text":"is_primary: true"},{"id":"c","text":"routing: write"},{"id":"d","text":"index.blocks.read: false"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$When an alias spans multiple indices, exactly one must have `is_write_index: true` so writes target the current rollover index while reads span all. The other options are not how a write target is designated.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/aliases.html","label":"Elasticsearch Reference — Aliases"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A write alias used by a data stream / rollover pattern must have exactly one index designated as:$ece$);
