INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which analyzer lowercases and splits on non-letter characters (dropping numbers)?$ece$, $ece$[{"id":"a","text":"simple analyzer"},{"id":"b","text":"standard analyzer"},{"id":"c","text":"keyword analyzer"},{"id":"d","text":"pattern analyzer with \\d+"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `simple` analyzer uses the lowercase tokenizer: it breaks on non-letters and lowercases, discarding digits. `standard` keeps numbers; `keyword` emits one token; the pattern option is a different configurable analyzer.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which analyzer lowercases and splits on non-letter characters (dropping numbers)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A `normalizer` differs from an `analyzer` in that a normalizer:$ece$, $ece$[{"id":"a","text":"Produces a single token (no tokenizer) and is used on keyword fields"},{"id":"b","text":"Can use any tokenizer"},{"id":"c","text":"Only works on text fields"},{"id":"d","text":"Runs at query time only"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$A normalizer has no tokenizer — it applies char/token filters (like lowercase, asciifolding) and emits ONE token, used to normalize `keyword` fields for case-insensitive exact matching.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `normalizer` differs from an `analyzer` in that a normalizer:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which `text` field parameter, when set to `false`, disables storing term positions and prevents `match_phrase`/proximity queries on that field?$ece$, $ece$[{"id":"a","text":"index_options / index_phrases-related settings (e.g. \"index_options\": \"freqs\")"},{"id":"b","text":"doc_values"},{"id":"c","text":"norms"},{"id":"d","text":"eager_global_ordinals"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Phrase/proximity queries need positional data; lowering `index_options` (e.g. to `freqs`, dropping positions) makes `match_phrase` impossible. `doc_values`/`norms`/`global_ordinals` affect aggregations/scoring, not phrase capability.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which `text` field parameter, when set to `false`, disables storing term positions and prevents `match_phrase`/proximity queries on that field?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which API gives a one-line cluster-wide health summary (status, node count, active shards %)?$ece$, $ece$[{"id":"a","text":"GET _cluster/health"},{"id":"b","text":"GET _cat/indices"},{"id":"c","text":"GET _nodes/stats"},{"id":"d","text":"GET _tasks"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The Cluster Health API returns overall status (green/yellow/red), node and shard counts, and percentages. `_cat/indices` is per-index; `_nodes/stats` is detailed per-node; `_tasks` lists running tasks.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-health.html","label":"Elasticsearch Reference — Cluster health API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API gives a one-line cluster-wide health summary (status, node count, active shards %)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$During a rolling restart you set allocation to "primaries". After the node returns, you should:$ece$, $ece$[{"id":"a","text":"Re-enable allocation with cluster.routing.allocation.enable: \"all\" so replicas recover"},{"id":"b","text":"Leave it at \"primaries\" permanently"},{"id":"c","text":"Delete unassigned replicas"},{"id":"d","text":"Force a full cluster restart"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$After the node rejoins, reset `cluster.routing.allocation.enable` to `all` so replica shards reallocate and the cluster returns to green. Leaving it restricted keeps replicas unassigned (yellow).$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-allocation-explain.html","label":"Elasticsearch Reference — Cluster allocation explain API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$During a rolling restart you set allocation to "primaries". After the node returns, you should:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which API lists currently running long tasks (e.g. reindex, force-merge) and allows cancellation?$ece$, $ece$[{"id":"a","text":"GET _tasks (and POST _tasks/<id>/_cancel)"},{"id":"b","text":"GET _cat/recovery"},{"id":"c","text":"GET _nodes/hot_threads"},{"id":"d","text":"GET _cluster/pending_tasks"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The Task Management API lists tasks and supports `_cancel`. `_cat/recovery` shows shard recovery; `hot_threads` profiles CPU; `pending_tasks` shows queued cluster-state changes, not cancelable user tasks.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-health.html","label":"Elasticsearch Reference — Cluster health API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API lists currently running long tasks (e.g. reindex, force-merge) and allows cancellation?$ece$);
