INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which aggregation returns multiple statistics (min, max, avg, sum, count) in one result?$ece$, $ece$[{"id":"a","text":"stats"},{"id":"b","text":"terms"},{"id":"c","text":"cardinality"},{"id":"d","text":"date_histogram"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `stats` metric aggregation returns count/min/max/avg/sum together (`extended_stats` adds variance/std-dev). `terms`/`date_histogram` are buckets; `cardinality` is distinct count only.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which aggregation returns multiple statistics (min, max, avg, sum, count) in one result?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Inside a `terms` bucket aggregation, adding a `top_hits` sub-aggregation does what?$ece$, $ece$[{"id":"a","text":"Returns the top matching document(s) per bucket (e.g. newest order per customer)"},{"id":"b","text":"Counts distinct values"},{"id":"c","text":"Computes a moving average"},{"id":"d","text":"Renames a field"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`top_hits` is a metric aggregation returning the highest-ranked documents within each parent bucket — ideal for "best/latest per group". It does not count distinct values or do pipeline math.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Inside a `terms` bucket aggregation, adding a `top_hits` sub-aggregation does what?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which ingest processor enriches a document with geographic data (city, country) from an IP address?$ece$, $ece$[{"id":"a","text":"geoip"},{"id":"b","text":"set"},{"id":"c","text":"grok"},{"id":"d","text":"foreach"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `geoip` processor looks up an IP in a GeoIP database and adds location fields. `set` assigns static/computed values, `grok` parses text, `foreach` iterates an array applying another processor.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/processors.html","label":"Elasticsearch Reference — Ingest processor reference"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which ingest processor enriches a document with geographic data (city, country) from an IP address?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$The `enrich` processor in an ingest pipeline is used to:$ece$, $ece$[{"id":"a","text":"Add data from a separate enrich index/policy based on a match field at ingest time"},{"id":"b","text":"Aggregate documents at search time"},{"id":"c","text":"Replicate shards"},{"id":"d","text":"Compress the document"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `enrich` processor augments incoming documents with reference data from a precomputed enrich index defined by an enrich policy (e.g. add product details by SKU). It is ingest-time, not a search aggregation.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/processors.html","label":"Elasticsearch Reference — Ingest processor reference"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$The `enrich` processor in an ingest pipeline is used to:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which pipeline aggregation computes the running total of a metric across ordered buckets?$ece$, $ece$[{"id":"a","text":"cumulative_sum"},{"id":"b","text":"derivative"},{"id":"c","text":"bucket_selector"},{"id":"d","text":"avg"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`cumulative_sum` is a parent pipeline aggregation that accumulates a metric across the ordered buckets. `derivative` gives bucket-to-bucket change, `bucket_selector` filters buckets, `avg` is a plain metric.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations-pipeline.html","label":"Elasticsearch Reference — Pipeline aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P2$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which pipeline aggregation computes the running total of a metric across ordered buckets?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which setting defines the directory where Elasticsearch stores its index data on disk?$ece$, $ece$[{"id":"a","text":"path.data"},{"id":"b","text":"path.logs"},{"id":"c","text":"path.repo"},{"id":"d","text":"path.home"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`path.data` is the data directory. `path.logs` is logs, `path.repo` is allowed snapshot filesystem repository locations, and `path.home` (ES_HOME) is the install root.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting defines the directory where Elasticsearch stores its index data on disk?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You want a dedicated ingest node that runs ingest pipelines but holds no shards. The correct `node.roles` is:$ece$, $ece$[{"id":"a","text":"node.roles: [ ingest ]"},{"id":"b","text":"node.roles: [ data, ingest ]"},{"id":"c","text":"node.roles: [ master ]"},{"id":"d","text":"node.ingest: only"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`node.roles: [ ingest ]` makes the node ingest-only (runs pipelines, holds no data). Including `data` would also store shards; `master` is unrelated; `node.ingest: only` is not valid syntax.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You want a dedicated ingest node that runs ingest pipelines but holds no shards. The correct `node.roles` is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$After 8.x security auto-configuration, how does a NEW node typically join the existing secured cluster?$ece$, $ece$[{"id":"a","text":"By copying the elasticsearch.yml verbatim"},{"id":"b","text":"By starting with an enrollment token generated on an existing node (elasticsearch-create-enrollment-token)"},{"id":"c","text":"By disabling TLS first"},{"id":"d","text":"By manually editing the keystore on every node"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$An enrollment token (from `bin/elasticsearch-create-enrollment-token -s node`) lets a new node automatically obtain the CA/TLS material and join the secured cluster. Copying yml or disabling TLS is incorrect/insecure.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$After 8.x security auto-configuration, how does a NEW node typically join the existing secured cluster?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$MULTI$ece$::"QType", $ece$Select ALL valid Elasticsearch node roles that can appear in `node.roles`.$ece$, $ece$[{"id":"a","text":"master"},{"id":"b","text":"data"},{"id":"c","text":"ingest"},{"id":"d","text":"coordinator"}]$ece$::jsonb, $ece$["a","b","c"]$ece$::jsonb, $ece$`master`, `data` (and data tiers like data_hot/data_warm), and `ingest` are valid roles, along with ml, transform, remote_cluster_client. There is no explicit `coordinator` role — a coordinating-only node uses an empty roles list.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Select ALL valid Elasticsearch node roles that can appear in `node.roles`.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$A document is indexed but does not appear in search results immediately. The most likely reason is:$ece$, $ece$[{"id":"a","text":"It is lost permanently."},{"id":"b","text":"It is not yet refreshed/searchable — by default the index refreshes about every 1 second."},{"id":"c","text":"The cluster is red."},{"id":"d","text":"The mapping rejected it silently."}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Newly indexed documents become searchable only after a refresh (default `index.refresh_interval` ~1s), unless you force `?refresh=true`/`wait_for`. The document is durably written to the translog regardless.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A document is indexed but does not appear in search results immediately. The most likely reason is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You want an ILM-managed time-series data stream to start writing to a new backing index when the current one reaches 50 GB or 30 days. Which ILM action achieves this?$ece$, $ece$[{"id":"a","text":"The `rollover` action in the hot phase"},{"id":"b","text":"The `shrink` action"},{"id":"c","text":"The `freeze` action"},{"id":"d","text":"The `delete` action"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `rollover` action (hot phase) creates a new backing index when size/age/doc conditions are met. `shrink` reduces shards, `delete` removes the index, `freeze` is deprecated/cold-related.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You want an ILM-managed time-series data stream to start writing to a new backing index when the current one reaches 50 GB or 30 days. Which ILM action achieves this?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$To restore a single index from an existing snapshot, you use:$ece$, $ece$[{"id":"a","text":"POST _snapshot/<repo>/<snapshot>/_restore with indices specified"},{"id":"b","text":"POST <index>/_reindex from the repository"},{"id":"c","text":"PUT <index>/_recovery"},{"id":"d","text":"GET _snapshot/<repo>/<snapshot>"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The restore API `POST _snapshot/<repo>/<snapshot>/_restore` (optionally with `indices` and rename patterns) restores selected indices. `GET _snapshot/...` only reads metadata; `_recovery` reports recovery progress.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/snapshot-restore.html","label":"Elasticsearch Reference — Snapshot and restore"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$To restore a single index from an existing snapshot, you use:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 4, $ece$SINGLE$ece$::"QType", $ece$A `_reindex` request needs to copy only documents where `region:"eu"`. How is this expressed?$ece$, $ece$[{"id":"a","text":"Add a `query` under `source` in the reindex body"},{"id":"b","text":"Reindex everything then delete the rest"},{"id":"c","text":"Use a `filter` at the top level of the reindex body"},{"id":"d","text":"It is not possible to filter a reindex"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `_reindex` body accepts `source.query` (a standard Query DSL query) to copy only matching documents. Filtering at reindex time is supported and preferred over copy-then-delete.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `_reindex` request needs to copy only documents where `region:"eu"`. How is this expressed?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which query matches an exact, non-analyzed value and is appropriate on a `keyword` field?$ece$, $ece$[{"id":"a","text":"match"},{"id":"b","text":"term"},{"id":"c","text":"match_phrase"},{"id":"d","text":"query_string with analysis"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$The `term` query looks for the exact indexed token and does not analyze the input — correct for `keyword`, numeric, and boolean fields. `match`/`match_phrase` analyze the query text.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/term-level-queries.html","label":"Elasticsearch Reference — Term-level queries"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which query matches an exact, non-analyzed value and is appropriate on a `keyword` field?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A `match_phrase` query on `"quick brown fox"` matches documents where:$ece$, $ece$[{"id":"a","text":"Any of the three terms appears anywhere"},{"id":"b","text":"All three terms appear in that order, adjacent (subject to slop)"},{"id":"c","text":"The exact untokenized string is stored"},{"id":"d","text":"Only the first term matches"}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$`match_phrase` requires the analyzed terms to appear in the same order and adjacent (positions), optionally allowing reordering/gaps via `slop`. It still uses the field analyzer.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/full-text-queries.html","label":"Elasticsearch Reference — Full text queries"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `match_phrase` query on `"quick brown fox"` matches documents where:$ece$);
