INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 4, $ece$SINGLE$ece$::"QType", $ece$A parameterized, reusable search defined server-side and invoked with runtime parameters is implemented with:$ece$, $ece$[{"id":"a","text":"A search template (stored Mustache script invoked via _search/template)"},{"id":"b","text":"An ingest pipeline"},{"id":"c","text":"A runtime field"},{"id":"d","text":"An index alias"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Search templates store a Mustache-templated query (via the scripts API) and are executed with `_search/template` by id and params — decoupling the query shape from the client. Aliases/pipelines/runtime fields serve other purposes.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-template.html","label":"Elasticsearch Reference — Search templates"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A parameterized, reusable search defined server-side and invoked with runtime parameters is implemented with:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which is the correct way to add a NEW field to an existing index mapping?$ece$, $ece$[{"id":"a","text":"PUT <index>/_mapping with the new field properties"},{"id":"b","text":"You must delete and recreate the index"},{"id":"c","text":"PUT <index>/_settings with the field"},{"id":"d","text":"It happens only via dynamic mapping; explicit addition is impossible"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$You CAN add new fields to an existing mapping with `PUT <index>/_mapping`. What you cannot do is change the type of an existing field. `_settings` is for index settings, not fields.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which is the correct way to add a NEW field to an existing index mapping?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$The default analyzer applied to `text` fields when none is specified is:$ece$, $ece$[{"id":"a","text":"the `standard` analyzer"},{"id":"b","text":"the `keyword` analyzer"},{"id":"c","text":"the `whitespace` analyzer"},{"id":"d","text":"no analyzer (text is stored verbatim)"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `standard` analyzer (standard tokenizer + lowercase token filter, Unicode-aware) is the default for `text` fields. `keyword` analyzer emits the whole input as one token; `whitespace` only splits on whitespace.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$The default analyzer applied to `text` fields when none is specified is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$MULTI$ece$::"QType", $ece$Select ALL true statements about Elasticsearch text analysis components.$ece$, $ece$[{"id":"a","text":"A tokenizer splits a character stream into tokens (e.g. the `standard` tokenizer)."},{"id":"b","text":"Token filters can add, remove, or modify tokens (e.g. `lowercase`, `stop`, `synonym`)."},{"id":"c","text":"Character filters operate on the token stream after tokenization."},{"id":"d","text":"A custom analyzer can combine char filters, one tokenizer, and multiple token filters."}]$ece$::jsonb, $ece$["a","b","d"]$ece$::jsonb, $ece$Character filters operate on the RAW character stream BEFORE tokenization, not after. Tokenizer splits into tokens; token filters transform them; a custom analyzer composes char filters + one tokenizer + token filters.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis-custom-analyzer.html","label":"Elasticsearch Reference — Create a custom analyzer"},{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Select ALL true statements about Elasticsearch text analysis components.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 4, $ece$SINGLE$ece$::"QType", $ece$You map an analyzed `text` field but also need fast exact-match filtering on its raw value. The most storage-efficient idiomatic solution is:$ece$, $ece$[{"id":"a","text":"A multi-field: text with a `.keyword` sub-field (type keyword, ignore_above)"},{"id":"b","text":"Two completely separate indices"},{"id":"c","text":"Enabling fielddata on the text field"},{"id":"d","text":"A separate runtime script field for every query"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$A multi-field indexes the same source both as `text` and `keyword` without duplicating the source field in your documents. Enabling fielddata on text is memory-heavy and discouraged for exact match/aggregations.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/multi-fields.html","label":"Elasticsearch Reference — multi-fields"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You map an analyzed `text` field but also need fast exact-match filtering on its raw value. The most storage-efficient idiomatic solution is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$A cluster health status of `red` indicates:$ece$, $ece$[{"id":"a","text":"All shards allocated; cluster healthy."},{"id":"b","text":"At least one PRIMARY shard is not allocated — some data is unavailable."},{"id":"c","text":"Only replica shards are unassigned."},{"id":"d","text":"The cluster is performing a rolling upgrade."}]$ece$::jsonb, $ece$["b"]$ece$::jsonb, $ece$Red means at least one primary shard is unassigned, so part of the data cannot be searched or indexed. Yellow = primaries OK but some replicas unassigned; green = all assigned.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-health.html","label":"Elasticsearch Reference — Cluster health API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A cluster health status of `red` indicates:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$For querying indices that live on a SEPARATE remote Elasticsearch cluster without moving the data, you use:$ece$, $ece$[{"id":"a","text":"Cross-cluster search (configured remote clusters, query `remote:index`)"},{"id":"b","text":"A bigger single index"},{"id":"c","text":"Snapshot then restore on every query"},{"id":"d","text":"An ingest pipeline"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Cross-cluster search registers remote clusters and lets a local cluster query them with `<remote>:<index>` notation. Snapshots/ingest pipelines do not provide federated search.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-cross-cluster-search.html","label":"Elasticsearch Reference — Cross-cluster search"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$For querying indices that live on a SEPARATE remote Elasticsearch cluster without moving the data, you use:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which ingest processor would you use to copy/rename an incoming field to a new field name before indexing?$ece$, $ece$[{"id":"a","text":"The `rename` processor"},{"id":"b","text":"The `terms` aggregation"},{"id":"c","text":"The `reindex` API"},{"id":"d","text":"The `match` query"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `rename` ingest processor renames a field within the document during ingest. Aggregations/queries are search-time; reindex is a bulk copy API, not an in-pipeline transform.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/processors.html","label":"Elasticsearch Reference — Ingest processor reference"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which ingest processor would you use to copy/rename an incoming field to a new field name before indexing?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You want average order value bucketed per day. The correct aggregation structure is:$ece$, $ece$[{"id":"a","text":"A `date_histogram` bucket aggregation (calendar/fixed interval) with a nested `avg` metric sub-aggregation"},{"id":"b","text":"A single `avg` metric aggregation only"},{"id":"c","text":"A `terms` aggregation on the date field"},{"id":"d","text":"A pipeline aggregation with no parent"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Bucket per day = `date_histogram` (e.g. `calendar_interval: day`); the per-bucket average is a nested `avg` sub-aggregation. A bare `avg` gives one global number; `terms` on a raw date is not time-bucketed; pipeline aggs need a parent.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You want average order value bucketed per day. The correct aggregation structure is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which directory does `path.logs` configure?$ece$, $ece$[{"id":"a","text":"Where Elasticsearch writes its log files"},{"id":"b","text":"Where index data is stored"},{"id":"c","text":"Where snapshots are written"},{"id":"d","text":"The install root"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`path.logs` sets the log output directory. `path.data` is index data, `path.repo` is snapshot filesystem repos, and `path.home` (ES_HOME) is the install root.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which directory does `path.logs` configure?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which `node.roles` makes a node capable of running machine learning jobs?$ece$, $ece$[{"id":"a","text":"node.roles: [ ml ]"},{"id":"b","text":"node.roles: [ data_ml ]"},{"id":"c","text":"node.roles: [ analytics ]"},{"id":"d","text":"node.ml.enabled: true only"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `ml` role designates an ML node. There is no `data_ml`/`analytics` role; `xpack.ml.enabled` is a feature toggle, but the node role keyword in `node.roles` is `ml`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which `node.roles` makes a node capable of running machine learning jobs?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which `node.roles` value supports running transforms (pivoting data into entity-centric indices)?$ece$, $ece$[{"id":"a","text":"transform"},{"id":"b","text":"pivot"},{"id":"c","text":"data_transform"},{"id":"d","text":"aggregator"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `transform` role lets a node run transform jobs. `pivot` is a transform concept, not a role; `data_transform`/`aggregator` are not valid roles.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which `node.roles` value supports running transforms (pivoting data into entity-centric indices)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$After installing via the tar.gz archive, where do `elasticsearch.yml`, `jvm.options`, and `log4j2.properties` live by default?$ece$, $ece$[{"id":"a","text":"In the `config/` directory under ES_HOME"},{"id":"b","text":"In `/etc/elasticsearch` always"},{"id":"c","text":"In `path.data`"},{"id":"d","text":"In the JVM classpath only"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$For the archive distributions config files are in `$ES_HOME/config`. The package (RPM/DEB) installs place them in `/etc/elasticsearch`. They are never in `path.data`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$After installing via the tar.gz archive, where do `elasticsearch.yml`, `jvm.options`, and `log4j2.properties` live by default?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which is true about file-realm vs native-realm users in Elasticsearch security?$ece$, $ece$[{"id":"a","text":"File realm users are defined in files on each node (managed with elasticsearch-users); native realm users are stored in a system index via the API"},{"id":"b","text":"Both are stored only in elasticsearch.yml"},{"id":"c","text":"Native realm users require LDAP"},{"id":"d","text":"File realm users are stored in the keystore"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The file realm keeps users in node-local files (managed by `bin/elasticsearch-users`); the native realm stores users in a hidden security index, managed via the user-management APIs/Kibana. Neither lives in `elasticsearch.yml` or the keystore.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which is true about file-realm vs native-realm users in Elasticsearch security?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$TRUE_FALSE$ece$::"QType", $ece$True or False: In Elasticsearch 8.x, basic authentication and TLS are part of the free Basic license.$ece$, $ece$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$True. Since 6.8/7.1 and continuing in 8.x, core security (TLS, native realm authentication, RBAC) is included in the free Basic license; advanced features (SSO, field-level security) need a paid tier.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/configuring-stack-security.html","label":"Elasticsearch Reference — Configure security"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$True or False: In Elasticsearch 8.x, basic authentication and TLS are part of the free Basic license.$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which setting controls how long a node waits to find a master before logging warnings / failing health (cluster formation timeout-related)?$ece$, $ece$[{"id":"a","text":"cluster.election.* / discovery timeouts in the discovery module"},{"id":"b","text":"http.max_content_length"},{"id":"c","text":"index.refresh_interval"},{"id":"d","text":"thread_pool.write.size"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Discovery/election timeout settings (in the discovery module) govern master discovery/election behavior. `http.max_content_length`, `refresh_interval`, and thread pool sizing are unrelated to cluster formation.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-discovery.html","label":"Elasticsearch Reference — Discovery and cluster formation"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which setting controls how long a node waits to find a master before logging warnings / failing health (cluster formation timeout-related)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$A dedicated master node should generally NOT also be a data node because:$ece$, $ece$[{"id":"a","text":"Heavy data/query load can destabilize the master and risk cluster stability"},{"id":"b","text":"Master nodes cannot store any settings"},{"id":"c","text":"It is forbidden by the API"},{"id":"d","text":"Data nodes cannot vote"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Separating master-eligible nodes from data load keeps the cluster-coordination function stable under heavy indexing/search. It is allowed (small clusters combine roles) but discouraged at scale.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/modules-node.html","label":"Elasticsearch Reference — Node roles"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A dedicated master node should generally NOT also be a data node because:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Installation and Configuration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which command-line tool can be used to safely remove a node's persisted cluster metadata for unsafe recovery scenarios?$ece$, $ece$[{"id":"a","text":"bin/elasticsearch-node"},{"id":"b","text":"bin/elasticsearch-keystore"},{"id":"c","text":"bin/elasticsearch-certutil"},{"id":"d","text":"bin/elasticsearch-sql-cli"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `elasticsearch-node` tool provides unsafe cluster bootstrap/detach/repair subcommands. `keystore` handles secrets, `certutil` certs, and `sql-cli` is the SQL client.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/settings.html","label":"Elasticsearch Reference — Configuring Elasticsearch"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which command-line tool can be used to safely remove a node's persisted cluster metadata for unsafe recovery scenarios?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which API updates a dynamic index setting such as `refresh_interval`?$ece$, $ece$[{"id":"a","text":"PUT <index>/_settings"},{"id":"b","text":"PUT <index>/_mapping"},{"id":"c","text":"POST <index>/_update"},{"id":"d","text":"PUT <index>/_doc"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`PUT /<index>/_settings` updates dynamic index settings (replicas, refresh interval, blocks). `_mapping` changes fields; `_update`/`_doc` operate on documents.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-create-index.html","label":"Elasticsearch Reference — Create index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API updates a dynamic index setting such as `refresh_interval`?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Disabling refresh during a large bulk load (`index.refresh_interval: -1`) primarily:$ece$, $ece$[{"id":"a","text":"Improves indexing throughput by avoiding frequent segment creation (re-enable/refresh afterwards)"},{"id":"b","text":"Makes documents immediately searchable"},{"id":"c","text":"Permanently prevents searching the index"},{"id":"d","text":"Deletes existing documents"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Setting `refresh_interval: -1` stops periodic refreshes, reducing segment churn and boosting bulk indexing speed. You re-enable it (or call `_refresh`) afterward so data becomes searchable. It does not delete data.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-create-index.html","label":"Elasticsearch Reference — Create index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Disabling refresh during a large bulk load (`index.refresh_interval: -1`) primarily:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$The translog in Elasticsearch exists to:$ece$, $ece$[{"id":"a","text":"Provide durability for operations not yet committed to a Lucene segment (recovered on restart/crash)"},{"id":"b","text":"Store query results"},{"id":"c","text":"Hold the mapping"},{"id":"d","text":"Cache aggregations"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The transaction log records indexing operations so they can be replayed after a crash before the next Lucene commit/flush. It is not for query results, mappings, or aggregation caching.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$The translog in Elasticsearch exists to:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A `_flush` operation on an index:$ece$, $ece$[{"id":"a","text":"Commits in-memory/translog data to Lucene and clears the translog"},{"id":"b","text":"Makes new documents searchable (like refresh)"},{"id":"c","text":"Deletes the index"},{"id":"d","text":"Merges all segments into one"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`_flush` performs a Lucene commit and trims the translog. `_refresh` is what makes documents searchable; `_forcemerge` merges segments; flush does not delete data.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `_flush` operation on an index:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which `op_type`/endpoint guarantees a document is only created and never overwrites an existing id?$ece$, $ece$[{"id":"a","text":"PUT <index>/_create/<id>"},{"id":"b","text":"PUT <index>/_doc/<id>"},{"id":"c","text":"POST <index>/_update/<id>"},{"id":"d","text":"POST <index>/_doc"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`PUT /<index>/_create/<id>` (equivalent to `op_type=create`) returns 409 if the id already exists, never overwriting. `_doc/<id>` overwrites; `_update` modifies; `POST /_doc` auto-generates a new id.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which `op_type`/endpoint guarantees a document is only created and never overwrites an existing id?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You want a `_reindex` to also run each document through an ingest pipeline. You specify:$ece$, $ece$[{"id":"a","text":"\"dest\": { \"index\": \"...\", \"pipeline\": \"my-pipeline\" }"},{"id":"b","text":"\"source\": { \"pipeline\": \"my-pipeline\" }"},{"id":"c","text":"A separate _ingest call after reindex"},{"id":"d","text":"It cannot be combined with a pipeline"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Reindex applies an ingest pipeline by setting `dest.pipeline`. The pipeline runs as documents are written to the destination. There is no `source.pipeline` option.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You want a `_reindex` to also run each document through an ingest pipeline. You specify:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 4, $ece$SINGLE$ece$::"QType", $ece$Which `_split` precondition must hold to split an index from 2 primary shards to 6?$ece$, $ece$[{"id":"a","text":"The index must be read-only and the target shard count must be a multiple of the source count"},{"id":"b","text":"The index must be empty"},{"id":"c","text":"Replicas must be set to 0 permanently"},{"id":"d","text":"The source must first be force-merged to one segment"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`_split` requires the source index to be read-only and the target primary count to be a multiple of the original (2 → 6 is 3×). Force-merge and emptiness are not requirements; replicas need not be permanently zero.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-reindex.html","label":"Elasticsearch Reference — Reindex API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which `_split` precondition must hold to split an index from 2 primary shards to 6?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which API rolls over a write alias / data stream to a new backing index when a condition is met?$ece$, $ece$[{"id":"a","text":"POST <alias>/_rollover with conditions (max_age, max_size, max_docs)"},{"id":"b","text":"POST <index>/_split"},{"id":"c","text":"PUT <index>/_settings"},{"id":"d","text":"POST <index>/_clone"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The Rollover API creates a new index and points the write alias/data stream at it when `max_age`/`max_primary_shard_size`/`max_docs` conditions are satisfied (ILM automates this). Split/clone/settings do not roll over.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API rolls over a write alias / data stream to a new backing index when a condition is met?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Indexing Data$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which is true about how a document update (`_update`) is implemented internally?$ece$, $ece$[{"id":"a","text":"Elasticsearch fetches the doc, applies the change, and re-indexes the whole document (Lucene docs are immutable)"},{"id":"b","text":"It mutates the Lucene segment in place"},{"id":"c","text":"It only changes the _source, not the inverted index"},{"id":"d","text":"It requires the index to be closed"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Lucene documents are immutable; an update is a get-modify-reindex (old doc marked deleted, new one written). It does not patch segments in place and does not require closing the index.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/docs-index_.html","label":"Elasticsearch Reference — Index API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which is true about how a document update (`_update`) is implemented internally?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$In a search request, which key holds the query definition?$ece$, $ece$[{"id":"a","text":"\"query\""},{"id":"b","text":"\"filter\""},{"id":"c","text":"\"where\""},{"id":"d","text":"\"match_criteria\""}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The top-level `"query"` object contains the Query DSL. There is no top-level `"filter"`/`"where"`/`"match_criteria"` key (filtering is done inside a `bool.filter`).$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl.html","label":"Elasticsearch Reference — Query DSL"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$In a search request, which key holds the query definition?$ece$);
