INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$By default Elasticsearch reports `hits.total` as `"relation": "gte"` and caps the exact count at 10,000. To get an exact total you set:$ece$, $ece$[{"id":"a","text":"\"track_total_hits\": true"},{"id":"b","text":"\"size\": 10001"},{"id":"c","text":"\"from\": 10000"},{"id":"d","text":"\"explain\": true"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`track_total_hits: true` forces an exact total hit count (at extra cost) instead of the default 10,000 lower-bound. Changing `size`/`from`/`explain` does not change total-hit tracking.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl.html","label":"Elasticsearch Reference — Query DSL"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$By default Elasticsearch reports `hits.total` as `"relation": "gte"` and caps the exact count at 10,000. To get an exact total you set:$ece$);
