INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 4, $ece$SINGLE$ece$::"QType", $ece$A `match_phrase_prefix` query is appropriate for:$ece$, $ece$[{"id":"a","text":"\"Search as you type\" where the last term is treated as a prefix and earlier terms must form a phrase"},{"id":"b","text":"Exact keyword matching"},{"id":"c","text":"Numeric range filtering"},{"id":"d","text":"Aggregating by term"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`match_phrase_prefix` matches the leading terms as a phrase and the final term as a prefix — useful for live phrase autocompletion. It is not for exact keyword, ranges, or aggregations.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/full-text-queries.html","label":"Elasticsearch Reference — Full text queries"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `match_phrase_prefix` query is appropriate for:$ece$);
