INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Queries$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which compound query lets you take the single best-scoring sub-query among several, with optional tie-breaking?$ece$, $ece$[{"id":"a","text":"dis_max"},{"id":"b","text":"bool with all in must"},{"id":"c","text":"constant_score"},{"id":"d","text":"boosting"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`dis_max` returns documents matching any sub-query and scores by the highest single sub-query score (plus `tie_breaker`). `bool/must` sums scores; `constant_score` flattens; `boosting` demotes.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl.html","label":"Elasticsearch Reference — Query DSL"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which compound query lets you take the single best-scoring sub-query among several, with optional tie-breaking?$ece$);
