INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Why are `text` fields generally NOT directly usable in a `terms` aggregation?$ece$, $ece$[{"id":"a","text":"Aggregating on analyzed text requires fielddata (heap-heavy) which is disabled by default; use a `.keyword` sub-field instead"},{"id":"b","text":"text fields are not indexed"},{"id":"c","text":"Aggregations only work on numbers"},{"id":"d","text":"text fields have no doc values and cannot be aggregated at all under any circumstance"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Aggregating analyzed `text` needs in-heap fielddata (default disabled to protect the heap). The idiomatic fix is to aggregate on the `keyword` multi-field, which uses doc values. (Fielddata can be enabled but is discouraged.)$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping-types.html","label":"Elasticsearch Reference — Field data types"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Why are `text` fields generally NOT directly usable in a `terms` aggregation?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which numeric type is the most space-efficient choice for a value that is always 0–255?$ece$, $ece$[{"id":"a","text":"byte"},{"id":"b","text":"long"},{"id":"c","text":"double"},{"id":"d","text":"keyword"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$A `byte` covers -128..127... but for 0–255 the smallest practical fits are `short`/`byte`; among the options `byte` is the most compact numeric (vs the 8-byte `long`/`double`). `keyword` is a string, not numeric.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping-types.html","label":"Elasticsearch Reference — Field data types"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which numeric type is the most space-efficient choice for a value that is always 0–255?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which mapping setting disables dynamic field detection so unknown fields are stored in `_source` but not indexed?$ece$, $ece$[{"id":"a","text":"\"dynamic\": false"},{"id":"b","text":"\"dynamic\": \"strict\""},{"id":"c","text":"\"enabled\": false"},{"id":"d","text":"\"index\": false"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`dynamic: false` keeps unknown fields in `_source` but does not index them (no errors). `dynamic: strict` rejects them; `enabled: false` disables an object entirely; `index: false` applies per existing field.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which mapping setting disables dynamic field detection so unknown fields are stored in `_source` but not indexed?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Setting `"enabled": false` on an object field means:$ece$, $ece$[{"id":"a","text":"The object is stored in _source but not parsed/indexed at all (not searchable/aggregatable)"},{"id":"b","text":"The whole index is disabled"},{"id":"c","text":"The field is deleted"},{"id":"d","text":"The field becomes a runtime field"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`enabled: false` tells Elasticsearch to store the object in `_source` without indexing its contents — useful for metadata blobs you only retrieve. It does not delete data or affect the rest of the index.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/mapping.html","label":"Elasticsearch Reference — Mapping"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Setting `"enabled": false` on an object field means:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which API simulates how an analyzer/custom chain tokenizes text, returning token text, position, and offsets?$ece$, $ece$[{"id":"a","text":"POST <index>/_analyze"},{"id":"b","text":"GET <index>/_mapping"},{"id":"c","text":"POST <index>/_validate/query"},{"id":"d","text":"GET _cat/analyzers"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The Analyze API returns the produced tokens (with positions/offsets/types) for given text and an analyzer or explicit char_filter/tokenizer/filter chain. `_mapping`/`_validate/query`/`_cat/analyzers` do not do this.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/indices-analyze.html","label":"Elasticsearch Reference — Analyze API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API simulates how an analyzer/custom chain tokenizes text, returning token text, position, and offsets?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$The `lowercase` token filter is applied:$ece$, $ece$[{"id":"a","text":"After the tokenizer, lowercasing each token"},{"id":"b","text":"Before the tokenizer, on raw characters"},{"id":"c","text":"As the tokenizer itself"},{"id":"d","text":"Only at query time"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`lowercase` is a token filter operating on tokens produced by the tokenizer. Lowercasing raw characters before tokenization would be a char filter; the `lowercase` tokenizer is a separate component.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis-custom-analyzer.html","label":"Elasticsearch Reference — Create a custom analyzer"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$The `lowercase` token filter is applied:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A `stemmer` token filter (e.g. English stemmer) does what?$ece$, $ece$[{"id":"a","text":"Reduces words to a root form (e.g. \"running\" → \"run\") so variants match"},{"id":"b","text":"Removes stop words"},{"id":"c","text":"Splits on whitespace"},{"id":"d","text":"Strips HTML"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$A stemmer normalizes inflected words to a common stem, improving recall (e.g. "runs/running/ran" → "run"). Stop-word removal is `stop`, whitespace splitting is a tokenizer, HTML stripping is `html_strip`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis-custom-analyzer.html","label":"Elasticsearch Reference — Create a custom analyzer"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `stemmer` token filter (e.g. English stemmer) does what?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Mappings and Text Analysis$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$You need exact, case-INSENSITIVE matching of email addresses. The best mapping is:$ece$, $ece$[{"id":"a","text":"A `keyword` field with a `normalizer` that applies a `lowercase` filter"},{"id":"b","text":"A `text` field with the standard analyzer"},{"id":"c","text":"A `keyword` field with no normalizer"},{"id":"d","text":"A runtime field that lowercases at query time only"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$A `keyword` field plus a lowercase `normalizer` indexes one normalized token, giving exact case-insensitive matching/aggregation. Plain `keyword` is case-sensitive; `text` tokenizes (splitting the address); a runtime field is slower per query.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/analysis.html","label":"Elasticsearch Reference — Text analysis"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$You need exact, case-INSENSITIVE matching of email addresses. The best mapping is:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which API shows shard recovery progress (bytes/percent) for indices being relocated or restored?$ece$, $ece$[{"id":"a","text":"GET _cat/recovery?v (or <index>/_recovery)"},{"id":"b","text":"GET _cat/health?v"},{"id":"c","text":"GET _cluster/settings"},{"id":"d","text":"GET _nodes/hot_threads"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`_cat/recovery` / `<index>/_recovery` report ongoing shard recovery progress. `_cat/health` is a summary, `_cluster/settings` shows config, `hot_threads` profiles CPU.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/cluster-health.html","label":"Elasticsearch Reference — Cluster health API"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which API shows shard recovery progress (bytes/percent) for indices being relocated or restored?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A searchable snapshot allows you to:$ece$, $ece$[{"id":"a","text":"Mount snapshot data as a (cold/frozen) index and search it without fully restoring it to local disk"},{"id":"b","text":"Search while taking the snapshot"},{"id":"c","text":"Convert a snapshot into an ingest pipeline"},{"id":"d","text":"Replicate a snapshot to another cluster automatically"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Searchable snapshots mount snapshot-backed indices (cold/frozen tiers) so data is queryable while residing primarily in the repository, cutting local storage cost. It is not about taking snapshots concurrently or CCR.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/snapshot-restore.html","label":"Elasticsearch Reference — Snapshot and restore"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A searchable snapshot allows you to:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$The ILM `allocate` action is commonly used to:$ece$, $ece$[{"id":"a","text":"Move an index to a different data tier/node attribute and/or change its replica count as it ages"},{"id":"b","text":"Delete the index"},{"id":"c","text":"Roll over to a new index"},{"id":"d","text":"Force-merge segments"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `allocate` action reassigns shards (e.g. to warm/cold nodes via allocation attributes) and can change `number_of_replicas`. Deletion is `delete`, rollover is `rollover`, segment merge is `forcemerge`.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$The ILM `allocate` action is commonly used to:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Cluster Administration$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which ILM action in the warm/cold phase reduces the number of primary shards of an index?$ece$, $ece$[{"id":"a","text":"shrink"},{"id":"b","text":"rollover"},{"id":"c","text":"allocate"},{"id":"d","text":"set_priority"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `shrink` action reduces primary shard count for older indices. `rollover` (hot) starts a new index, `allocate` moves/changes replicas/tiering, `set_priority` orders recovery.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/index-lifecycle-management.html","label":"Elasticsearch Reference — Index lifecycle management"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which ILM action in the warm/cold phase reduces the number of primary shards of an index?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 2, $ece$SINGLE$ece$::"QType", $ece$Which aggregation buckets numeric values into fixed-width intervals (e.g. every 10 units)?$ece$, $ece$[{"id":"a","text":"histogram"},{"id":"b","text":"terms"},{"id":"c","text":"avg"},{"id":"d","text":"cardinality"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `histogram` bucket aggregation groups numeric values into fixed `interval`-width buckets (`date_histogram` is its time variant). `terms` buckets by distinct value; `avg`/`cardinality` are metrics.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which aggregation buckets numeric values into fixed-width intervals (e.g. every 10 units)?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A `filters` (plural) aggregation lets you:$ece$, $ece$[{"id":"a","text":"Define multiple named buckets, each based on its own query/filter"},{"id":"b","text":"Filter the query before searching"},{"id":"c","text":"Remove a field"},{"id":"d","text":"Compute an average"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `filters` aggregation creates one bucket per supplied named filter (plus an optional "other" bucket) — handy for categorizing docs by arbitrary conditions. It is not a query-level filter or a metric.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `filters` (plural) aggregation lets you:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$Which ingest processor conditionally runs another processor only when a script/condition is true?$ece$, $ece$[{"id":"a","text":"Using the `if` parameter on a processor (painless condition)"},{"id":"b","text":"The `terms` aggregation"},{"id":"c","text":"The `bool` query"},{"id":"d","text":"The `reindex` API"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$Any ingest processor can take an `if` condition (a Painless expression) so it executes only when the condition holds. Aggregations/queries are search-time; reindex is a bulk copy, not conditional logic.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/processors.html","label":"Elasticsearch Reference — Ingest processor reference"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$Which ingest processor conditionally runs another processor only when a script/condition is true?$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$The `script` ingest processor is used to:$ece$, $ece$[{"id":"a","text":"Run a Painless script to compute or transform fields during ingest"},{"id":"b","text":"Run a search-time aggregation"},{"id":"c","text":"Define an analyzer"},{"id":"d","text":"Schedule a snapshot"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$The `script` processor executes Painless against the document at ingest time (e.g. derive fields). It is not a search aggregation, analyzer, or snapshot mechanism.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/processors.html","label":"Elasticsearch Reference — Ingest processor reference"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$The `script` ingest processor is used to:$ece$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $ece$Data Processing and Aggregations$ece$, 3, $ece$SINGLE$ece$::"QType", $ece$A `significant_terms` aggregation surfaces:$ece$, $ece$[{"id":"a","text":"Terms that are unusually frequent in the query result set compared to the background corpus"},{"id":"b","text":"The most frequent terms overall only"},{"id":"c","text":"A moving average"},{"id":"d","text":"Distinct value counts"}]$ece$::jsonb, $ece$["a"]$ece$::jsonb, $ece$`significant_terms` finds terms over-represented in the foreground (matching) set relative to the background, highlighting "interesting" terms. Plain `terms` shows raw frequency; cardinality counts distinct values.$ece$, $ece$[{"url":"https://www.elastic.co/guide/en/elasticsearch/reference/current/search-aggregations.html","label":"Elasticsearch Reference — Aggregations"}]$ece$::jsonb, $ece$PUBLISHED$ece$::"QStatus", $ece$manual:elastic-seed$ece$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $ece$CERTIFIED-ENGINEER-P3$ece$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $ece$A `significant_terms` aggregation surfaces:$ece$);
